import lxml.etree as ET

def process_soap_request(xml_string):
    # Validate the XML against the DTD
    root = ET.fromstring(xml_string)
    if not root.getroottree().docinfo.external_subset:
        raise ValueError("DTD validation failed")

    # Extract the message body from the SOAP envelope
    body = root.find(".//Body")
    if body is None:
        raise ValueError("No message body found in SOAP envelope")

    return body.text